module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output reg mul_en_out,
    output reg mul_out
);
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] partial_products [7:0];
reg [15:0] sum [7:0];
reg [7:0] carry [7:0];
reg [3:0] stage;
wire [15:0] temp [7:0];
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_en_out <= 1'b0;
        mul_out <= 16'b0;
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
        stage <= 4'b0;
    end
    else begin
        mul_en_out <= mul_en_in;
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
        if (mul_en_in) begin
            for (int i = 0; i < 8; i++) begin
                partial_products[i] <= mul_a_reg[i] ? {8'b0, mul_b_reg} << i : 16'b0;
            end
            stage <= 4'b1000;
        end
        else begin
            stage <= 4'b0;
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        for (int i = 0; i < 8; i++) begin
            sum[i] <= 16'b0;
            carry[i] <= 8'b0;
        end
    end
    else begin
        if (stage[3]) begin
            for (int i = 0; i < 8; i++) begin
                {carry[i], sum[i]} <= partial_products[i] + (i == 0 ? 16'b0 : sum[i-1]);
            end
            stage <= {stage[2:0], 1'b0};
        end
        else begin
            for (int i = 0; i < 8; i++) begin
                sum[i] <= sum[i];
                carry[i] <= carry[i];
            end
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 16'b0;
    end
    else begin
        if (stage[3]) begin
            mul_out <= sum[7];
        end
        else begin
            mul_out <= mul_out;
        end
    end
end
assign temp[0] = {8'b0, mul_b_reg[0:0]};
assign temp[1] = {7'b0, mul_b_reg[1:0]};
assign temp[2] = {6'b0, mul_b_reg[2:0]};
assign temp[3] = {5'b0, mul_b_reg[3:0]};
assign temp[4] = {4'b0, mul_b_reg[4:0]};
assign temp[5] = {3'b0, mul_b_reg[5:0]};
assign temp[6] = {2'b0, mul_b_reg[6:0]};
assign temp[7] = {1'b0, mul_b_reg[7:0]};
endmodule

