<module id="multi_pipe_8bit">
    <description>Unsigned 8-bit multiplier implemented with pipelining. Utilizes clock (clk), active-low reset (rst_n), input enable (mul_en_in), and outputs enable (mul_en_out) and product (mul_out).</description>
    <ports>
        <input id="clk">Clock signal for synchronization.</input>
        <input id="rst_n">Active-low reset signal.</input>
        <input id="mul_en_in">Input enable signal for multiplication operation.</input>
        <input id="mul_a" width_description="[7:0]">Multiplicand input signal.</input>
        <input id="mul_b" width_description="[7:0]">Multiplier input signal.</input>
        <output id="mul_en_out">Output enable signal indicating multiplication operation status.</output>
        <output id="mul_out" width_description="[15:0]">Product output signal.</output>
    </ports>
    <logic_description type="sequential_logic">
        <register id="mul_en_out_reg" width="4" description="Register to hold the input enable signal for output control."/>
        <register id="mul_a_reg" width="8" description="Register to store the multiplicand input."/>
        <register id="mul_b_reg" width="8" description="Register to store the multiplier input."/>
        <wire id="temp" width="8" description="Wires to hold temporary partial products."/>
        <register id="sum" width="9" description="Registers to store intermediate sum values."/>
        <register id="mul_out_reg" width="16" description="Register to accumulate the final product."/>
    </logic_description>
    <implementation>
        // Pipeline stages
        // Stage 1: Input Control
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                mul_en_out_reg <= 4'b0;
            end else begin
                mul_en_out_reg <= {mul_en_out_reg[2:0], mul_en_in};
            end
        end

        // Stage 2: Input Registers
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                mul_a_reg <= 8'b0;
                mul_b_reg <= 8'b0;
            end else if (mul_en_out_reg[3]) begin
                mul_a_reg <= mul_a;
                mul_b_reg <= mul_b;
            end
        end

        // Stage 3: Partial Product Generation
        assign temp[0] = mul_a_reg & {8{mul_b_reg[0]}};
        assign temp[1] = mul_a_reg & {8{mul_b_reg[1]}};
        assign temp[2] = mul_a_reg & {8{mul_b_reg[2]}};
        assign temp[3] = mul_a_reg & {8{mul_b_reg[3]}};
        assign temp[4] = mul_a_reg & {8{mul_b_reg[4]}};
        assign temp[5] = mul_a_reg & {8{mul_b_reg[5]}};
        assign temp[6] = mul_a_reg & {8{mul_b_reg[6]}};
        assign temp[7] = mul_a_reg & {8{mul_b_reg[7]}};

        // Stage 4: Partial Sum Calculation
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                sum[0] <= 9'b0;
                sum[1] <= 9'b0;
                sum[2] <= 9'b0;
                sum[3] <= 9'b0;
                sum[4] <= 9'b0;
                sum[5] <= 9'b0;
                sum[6] <= 9'b0;
                sum[7] <= 9'b0;
            end else begin
                sum[0] <= temp[0];
                sum[1] <= sum[0] + temp[1];
                sum[2] <= sum[1] + temp[2];
                sum[3] <= sum[2] + temp[3];
                sum[4] <= sum[3] + temp[4];
                sum[5] <= sum[4] + temp[5];
                sum[6] <= sum[5] + temp[6];
                sum[7] <= sum[6] + temp[7];
            end
        end

        // Stage 5: Final Product Calculation
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                mul_out_reg <= 16'b0;
            end else begin
                mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3] + sum[4] + sum[5] + sum[6] + sum[7];
            end
        end

        // Stage 6: Output Assignment
        assign mul_en_out = mul_en_out_reg[3];
        assign mul_out = mul_en_out ? mul_out_reg : 16'b0;
    </implementation>
</module>
